                try
                {
                    var orderGroup = new OrderDataGroup
                    {
                        OrderNumber = orderData.OrderNumber,
                        OrderDate = DateTime.ParseExact(orderData.Date, new[] { "dd/MM/yyyy", "d/M/yyyy", "dd/M/yyyy", "d/MM/yyyy" }, CultureInfo.InvariantCulture, DateTimeStyles.None),
                        CustomerName = orderData.CustomerName,
                        PhoneNumber = orderData.Phone == "N/A" ? null : orderData.Phone?.Replace(" ", ""),
                        Address = orderData.Address,
                        PaymentMethod = orderData.PaymentMethod,
                        OrderStatus = orderData.OrderStatus,
                        PaymentStatus = orderData.PaymentStatus,
                        TotalAmount = orderData.Total,
                        ShippingFee = orderData.Notes.Contains("ship") || orderData.Notes.Contains("30k") ? 30000 : 0,
                        Notes = orderData.Notes,
                        Items = orderData.Items.Select(item => new OrderItemData
                        {
                            ProductName = "Túi Tote",
                            Color = item.Color,
                            Quantity = item.Qty,
                            UnitPrice = item.Price
                        }).ToList()
                    };

                    orders.Add(orderGroup);
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"Error parsing order {orderData.OrderNumber}: {ex.Message}");
                }
            }

            return orders;
